import { useForm } from '@tanstack/react-form'
import { roles } from './data'

function FieldError({ field }) {
  return field.state.meta.isTouched && field.state.meta.errors.length > 0 ? (
    <span className="field-error">{field.state.meta.errors[0]}</span>
  ) : null
}

export default function EditableRow({ row, onSave, onCancel }) {
  const form = useForm({
    defaultValues: {
      name: row.name,
      email: row.email,
      role: row.role,
    },
    onSubmit: async ({ value }) => {
      onSave({ ...row, ...value })
    },
  })

  return (
    <tr className="editing-row">
      <td>{row.id}</td>

      {/* Name field */}
      <td>
        <form.Field
          name="name"
          validators={{
            onChange: ({ value }) =>
              !value || value.trim() === ''
                ? 'Name is required'
                : value.trim().length < 2
                ? 'Name must be at least 2 characters'
                : undefined,
          }}
        >
          {(field) => (
            <div className="field-wrapper">
              <input
                className={`edit-input ${field.state.meta.isTouched && field.state.meta.errors.length ? 'input-error' : ''}`}
                value={field.state.value}
                onChange={(e) => field.handleChange(e.target.value)}
                onBlur={field.handleBlur}
                placeholder="Full name"
              />
              <FieldError field={field} />
            </div>
          )}
        </form.Field>
      </td>

      {/* Email field */}
      <td>
        <form.Field
          name="email"
          validators={{
            onChange: ({ value }) => {
              if (!value || value.trim() === '') return 'Email is required'
              const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/
              if (!emailRegex.test(value.trim())) return 'Must be a valid email address'
              return undefined
            },
          }}
        >
          {(field) => (
            <div className="field-wrapper">
              <input
                className={`edit-input ${field.state.meta.isTouched && field.state.meta.errors.length ? 'input-error' : ''}`}
                value={field.state.value}
                onChange={(e) => field.handleChange(e.target.value)}
                onBlur={field.handleBlur}
                placeholder="Email address"
                type="email"
              />
              <FieldError field={field} />
            </div>
          )}
        </form.Field>
      </td>

      {/* Role field */}
      <td>
        <form.Field
          name="role"
          validators={{
            onChange: ({ value }) =>
              !value ? 'Role is required' : undefined,
          }}
        >
          {(field) => (
            <div className="field-wrapper">
              <select
                className={`edit-select ${field.state.meta.isTouched && field.state.meta.errors.length ? 'input-error' : ''}`}
                value={field.state.value}
                onChange={(e) => field.handleChange(e.target.value)}
                onBlur={field.handleBlur}
              >
                {roles.map((r) => (
                  <option key={r} value={r}>
                    {r}
                  </option>
                ))}
              </select>
              <FieldError field={field} />
            </div>
          )}
        </form.Field>
      </td>

      {/* Actions */}
      <td>
        <div className="action-buttons">
          <form.Subscribe
            selector={(state) => [state.canSubmit, state.isSubmitting]}
          >
            {([canSubmit, isSubmitting]) => (
              <button
                className="btn btn-save"
                type="button"
                disabled={isSubmitting}
                onClick={() => form.handleSubmit()}
              >
                {isSubmitting ? 'Saving…' : 'Save'}
              </button>
            )}
          </form.Subscribe>
          <button className="btn btn-cancel" type="button" onClick={onCancel}>
            Cancel
          </button>
        </div>
      </td>
    </tr>
  )
}

import { useState, useCallback } from 'react'
import {
  useReactTable,
  getCoreRowModel,
  flexRender,
  createColumnHelper,
} from '@tanstack/react-table'
import { initialUsers } from './data'
import EditableRow from './EditableRow'

const columnHelper = createColumnHelper()

const displayColumns = [
  columnHelper.accessor('id', {
    header: 'ID',
    cell: (info) => info.getValue(),
  }),
  columnHelper.accessor('name', {
    header: 'Name',
    cell: (info) => info.getValue(),
  }),
  columnHelper.accessor('email', {
    header: 'Email',
    cell: (info) => info.getValue(),
  }),
  columnHelper.accessor('role', {
    header: 'Role',
    cell: (info) => (
      <span className={`role-badge role-${info.getValue().toLowerCase()}`}>
        {info.getValue()}
      </span>
    ),
  }),
  columnHelper.display({
    id: 'actions',
    header: 'Actions',
    cell: () => null, // rendered manually
  }),
]

export default function UserTable() {
  const [data, setData] = useState(initialUsers)
  const [editingId, setEditingId] = useState(null)

  const table = useReactTable({
    data,
    columns: displayColumns,
    getCoreRowModel: getCoreRowModel(),
  })

  const handleEdit = useCallback((id) => setEditingId(id), [])
  const handleCancel = useCallback(() => setEditingId(null), [])

  const handleSave = useCallback(
    (updatedUser) => {
      setData((prev) =>
        prev.map((u) => (u.id === updatedUser.id ? updatedUser : u))
      )
      setEditingId(null)
    },
    []
  )

  return (
    <div className="table-container">
      <table className="user-table">
        <thead>
          {table.getHeaderGroups().map((headerGroup) => (
            <tr key={headerGroup.id}>
              {headerGroup.headers.map((header) => (
                <th key={header.id}>
                  {flexRender(
                    header.column.columnDef.header,
                    header.getContext()
                  )}
                </th>
              ))}
            </tr>
          ))}
        </thead>
        <tbody>
          {table.getRowModel().rows.map((row) => {
            const user = row.original

            if (editingId === user.id) {
              return (
                <EditableRow
                  key={user.id}
                  row={user}
                  onSave={handleSave}
                  onCancel={handleCancel}
                />
              )
            }

            return (
              <tr key={user.id} className="display-row">
                {row.getVisibleCells().map((cell) => {
                  if (cell.column.id === 'actions') {
                    return (
                      <td key={cell.id}>
                        <button
                          className="btn btn-edit"
                          onClick={() => handleEdit(user.id)}
                          disabled={editingId !== null}
                        >
                          Edit
                        </button>
                      </td>
                    )
                  }
                  return (
                    <td key={cell.id}>
                      {flexRender(cell.column.columnDef.cell, cell.getContext())}
                    </td>
                  )
                })}
              </tr>
            )
          })}
        </tbody>
      </table>
    </div>
  )
}

