/* =========================================================
   App Layout
   ========================================================= */
*,
*::before,
*::after {
  box-sizing: border-box;
}

body {
  margin: 0;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen,
    Ubuntu, Cantarell, sans-serif;
  background: #f0f2f5;
  color: #1a1a2e;
}

.app {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

.app-header {
  background: linear-gradient(135deg, #1a1a2e 0%, #16213e 60%, #0f3460 100%);
  color: #fff;
  padding: 32px 40px 28px;
  box-shadow: 0 2px 12px rgba(0, 0, 0, 0.25);
}

.app-header h1 {
  margin: 0 0 6px;
  font-size: 1.9rem;
  font-weight: 700;
  letter-spacing: -0.5px;
}

.subtitle {
  margin: 0;
  font-size: 0.95rem;
  opacity: 0.75;
}

.app-main {
  padding: 32px 40px;
  flex: 1;
}

/* =========================================================
   Table Container
   ========================================================= */
.table-container {
  background: #ffffff;
  border-radius: 12px;
  box-shadow: 0 4px 24px rgba(0, 0, 0, 0.08);
  overflow: hidden;
}

/* =========================================================
   User Table
   ========================================================= */
.user-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.92rem;
}

.user-table thead {
  background: #1a1a2e;
  color: #e0e0e0;
}

.user-table th {
  padding: 14px 20px;
  text-align: left;
  font-weight: 600;
  font-size: 0.8rem;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  white-space: nowrap;
}

.user-table tbody tr {
  border-bottom: 1px solid #eef0f4;
  transition: background 0.15s;
}

.user-table tbody tr:last-child {
  border-bottom: none;
}

.display-row:hover {
  background: #f8f9ff;
}

.editing-row {
  background: #fffbf0;
  box-shadow: inset 0 0 0 2px #f59e0b;
}

.user-table td {
  padding: 12px 20px;
  vertical-align: middle;
}

/* =========================================================
   Role Badges
   ========================================================= */
.role-badge {
  display: inline-block;
  padding: 3px 10px;
  border-radius: 999px;
  font-size: 0.78rem;
  font-weight: 600;
  letter-spacing: 0.03em;
}

.role-admin {
  background: #fee2e2;
  color: #b91c1c;
}

.role-editor {
  background: #dbeafe;
  color: #1d4ed8;
}

.role-viewer {
  background: #d1fae5;
  color: #065f46;
}

/* =========================================================
   Buttons
   ========================================================= */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 6px 14px;
  border-radius: 6px;
  font-size: 0.83rem;
  font-weight: 600;
  cursor: pointer;
  border: 1.5px solid transparent;
  transition: background 0.15s, border-color 0.15s, opacity 0.15s;
  white-space: nowrap;
}

.btn:disabled {
  opacity: 0.55;
  cursor: not-allowed;
}

.btn-edit {
  background: #eff6ff;
  color: #2563eb;
  border-color: #bfdbfe;
}

.btn-edit:hover:not(:disabled) {
  background: #dbeafe;
  border-color: #93c5fd;
}

.btn-edit:disabled {
  background: #f1f5f9;
  color: #94a3b8;
  border-color: #e2e8f0;
}

.btn-save {
  background: #059669;
  color: #fff;
  border-color: #047857;
}

.btn-save:hover:not(:disabled) {
  background: #047857;
}

.btn-cancel {
  background: #f1f5f9;
  color: #475569;
  border-color: #cbd5e1;
}

.btn-cancel:hover:not(:disabled) {
  background: #e2e8f0;
  border-color: #94a3b8;
}

.action-buttons {
  display: flex;
  gap: 8px;
  align-items: center;
}

/* =========================================================
   Edit Inputs
   ========================================================= */
.field-wrapper {
  display: flex;
  flex-direction: column;
  gap: 3px;
}

.edit-input,
.edit-select {
  padding: 6px 10px;
  border: 1.5px solid #d1d5db;
  border-radius: 6px;
  font-size: 0.88rem;
  background: #fff;
  color: #111827;
  outline: none;
  transition: border-color 0.15s, box-shadow 0.15s;
  width: 100%;
  min-width: 140px;
}

.edit-input:focus,
.edit-select:focus {
  border-color: #3b82f6;
  box-shadow: 0 0 0 3px rgba(59, 130, 246, 0.15);
}

.input-error {
  border-color: #ef4444 !important;
  box-shadow: 0 0 0 3px rgba(239, 68, 68, 0.12) !important;
}

.field-error {
  font-size: 0.75rem;
  color: #dc2626;
  font-weight: 500;
  display: flex;
  align-items: center;
  gap: 3px;
}

.field-error::before {
  content: '⚠';
  font-size: 0.7rem;
}

/* =========================================================
   Responsive
   ========================================================= */
@media (max-width: 768px) {
  .app-header {
    padding: 20px;
  }

  .app-main {
    padding: 16px;
  }

  .user-table th,
  .user-table td {
    padding: 10px 12px;
  }

  .edit-input,
  .edit-select {
    min-width: 100px;
  }
}

